theme.custom_css_code:
.yeti-wrap{font-family:Arial,sans-serif;color:#fff;background:transparent}
.yeti-card{background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.18);border-radius:18px;padding:20px;box-sizing:border-box;backdrop-filter:blur(4px)}
.yeti-scroll{overflow-x:auto;-webkit-overflow-scrolling:touch}
.yeti-table{width:100%;min-width:680px;border-collapse:collapse;font-size:14px;line-height:1.45}
.yeti-table td{padding:12px 14px;border-bottom:1px solid rgba(255,255,255,.14);vertical-align:top}
.yeti-table tr:last-child td{border-bottom:none}
.yeti-table td:first-child{width:34%;font-weight:700;color:#d9f1ff}
.yeti-muted{color:rgba(255,255,255,.82)}
.yeti-chart{display:grid;gap:14px}
.yeti-bar-row{display:grid;grid-template-columns:150px 1fr 56px;gap:12px;align-items:center}
.yeti-label{font-size:14px;font-weight:700;color:#e9f8ff}
.yeti-track{height:14px;background:rgba(255,255,255,.12);border-radius:999px;overflow:hidden;position:relative}
.yeti-fill{height:100%;border-radius:999px;background:linear-gradient(90deg,#8ee3ff 0%,#dff8ff 100%);box-shadow:0 0 14px rgba(142,227,255,.35)}
.yeti-value{font-size:13px;text-align:right;color:#d9f1ff;font-weight:700}
.yeti-legend{display:flex;flex-wrap:wrap;gap:10px;margin-top:6px}
.yeti-legend span{display:inline-flex;align-items:center;gap:8px;font-size:12px;color:#d9f1ff}
.yeti-dot{width:10px;height:10px;border-radius:50%}
.yeti-grid-2{display:grid;grid-template-columns:1fr;gap:18px}
@media (min-width:900px){.yeti-grid-2{grid-template-columns:1fr 1fr}}
